import React, { useEffect, useRef, useMemo } from "react";
import { MapContainer, TileLayer, Marker, Popup, Polygon, useMap, Tooltip } from "react-leaflet";
import MarkerClusterGroup from "react-leaflet-cluster";
import "leaflet/dist/leaflet.css";
import "leaflet.markercluster/dist/MarkerCluster.css";
import "leaflet.markercluster/dist/MarkerCluster.Default.css";
import L from "leaflet";
import { ZoneInfo, CameraInfo, LEVEL_MAP, SiteInfo, MOCK_SITES } from "../data/mockData";
import { Card, theme } from "antd";
import { GlobalOutlined } from "@ant-design/icons";
import { useI18n } from "@/framework/i18n/hooks";
import { MockVideoPlayer } from "../hooks/useCameraMock";

const { useToken } = theme;

// Fix for icon issues in react-leaflet
delete (L.Icon.Default.prototype as any)._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: "https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png",
  iconUrl: "https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png",
  shadowUrl: "https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png",
});

const siteIcon = new L.Icon({
  iconUrl: "https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-2x-orange.png",
  shadowUrl: "https://cdnjs.cloudflare.com/ajax/libs/leaflet/0.7.7/images/marker-shadow.png",
  iconSize: [35, 52],
  iconAnchor: [17, 52],
  popupAnchor: [1, -45],
  shadowSize: [52, 52]
});

const getCameraIcon = (level: number, isSelected: boolean) => {
  const status = level <= 2 ? "normal" : level === 3 ? "warning" : level === 4 ? "inspection" : "error";
  return new L.Icon({
    iconUrl: `/assets/platforms/crowdsafe/marker/crowd_${status}.png`,
    iconSize: isSelected ? [42, 42] : [32, 32],
    iconAnchor: isSelected ? [21, 21] : [16, 16],
    popupAnchor: [0, -20],
    className: isSelected ? "selected-camera-icon" : ""
  });
};


const getSiteBoundary = (siteId: string, zones: ZoneInfo[]): [number, number][] => {
  const siteZones = zones.filter(z => z.siteId === siteId);
  if (siteZones.length === 0) return [];
  
  let minLat = 90, maxLat = -90, minLng = 180, maxLng = -180;
  siteZones.forEach(z => {
    z.boundary.forEach(([lat, lng]) => {
      minLat = Math.min(minLat, lat);
      maxLat = Math.max(maxLat, lat);
      minLng = Math.min(minLng, lng);
      maxLng = Math.max(maxLng, lng);
    });
  });

  const padding = 0.0008;
  return [
    [minLat - padding, minLng - padding],
    [minLat - padding, maxLng + padding],
    [maxLat + padding, maxLng + padding],
    [maxLat + padding, minLng - padding]
  ];
};

function MapController({ 
  selectedCamera, 
  selectedSite,
  isMaximized,
  selectedCameraId,
  markerRefs
}: { 
  selectedCamera?: CameraInfo | null;
  selectedSite?: SiteInfo | null;
  isMaximized?: boolean;
  selectedCameraId?: number | null;
  markerRefs: React.MutableRefObject<Record<number, L.Marker | null>>;
}) {
  const map = useMap();

  useEffect(() => {
    if (selectedCamera) {
      // 1. Move to the exact location
      map.setView([selectedCamera.lat, selectedCamera.lng], 19, { animate: true, duration: 0.5 });
      
      // 2. Adjust pan to move marker towards the bottom so the popup is centered
      const timer = setTimeout(() => {
        map.panBy([0, -100], { animate: true, duration: 0.4 });
      }, 550);
      return () => clearTimeout(timer);
    } else if (selectedSite) {
      map.flyTo(selectedSite.location, 16, { animate: true, duration: 0.8 });
    }
  }, [selectedCamera, selectedSite, map]);

  useEffect(() => {
    if (!selectedCameraId) return;

    // Immediately close any existing popups to prevent state mismatch
    map.closePopup();

    // Retry multiple times to ensure popup opens after flyTo/unclustering completes
    const attemptOpen = (delay: number) => {
      return setTimeout(() => {
        const marker = markerRefs.current[selectedCameraId];
        if (marker) {
          marker.openPopup();
        }
      }, delay);
    };

    const timers = [
      attemptOpen(100), // Quick attempt for already unclustered markers
      attemptOpen(600), // After setView/flyTo completes
      attemptOpen(1200),
      attemptOpen(2000)
    ];

    return () => timers.forEach(t => clearTimeout(t));
  }, [selectedCameraId, map, markerRefs]);

  useEffect(() => {
    const timer = setTimeout(() => {
      map.invalidateSize({ animate: true });
    }, 400);
    return () => clearTimeout(timer);
  }, [isMaximized, map]);
  return null;
}

interface Props {
  sites: SiteInfo[];
  zones: ZoneInfo[];
  cameras: CameraInfo[];
  selectedSiteId?: string | null;
  selectedZoneId?: string | null;
  selectedCameraId?: number | null;
  onSiteSelect: (id: string) => void;
  onZoneSelect: (id: string) => void;
  onCameraSelect: (id: number) => void;
  extra?: React.ReactNode;
  isMaximized?: boolean;
}

const CrowdOSMMap: React.FC<Props> = ({ 
  sites,
  zones, 
  cameras, 
  selectedSiteId,
  selectedZoneId, 
  selectedCameraId,
  onSiteSelect,
  onZoneSelect,
  onCameraSelect,
  extra,
  isMaximized
}) => {
  const { token } = useToken();
  const { t } = useI18n(["dashboard"]);
  const initialCenter = MOCK_SITES[0].location;
  const activeCamera = cameras.find(c => c.id === selectedCameraId);
  const activeSite = sites.find(s => s.id === selectedSiteId);
  const markerRefs = useRef<Record<number, L.Marker | null>>({});

  const siteBoundaries = useMemo(() => {
    return sites.map(site => ({
      id: site.id,
      boundary: getSiteBoundary(site.id, zones)
    }));
  }, [sites, zones]);

  // Move map-related effects inside the controller component (must be child of MapContainer)

  return (
    <Card 
      title={
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <GlobalOutlined style={{ color: token.colorPrimary }} />
          <span style={{ color: token.colorText }}>{t("map.title")}</span>
        </div>
      }
      extra={extra}
      size="small"
      style={{ height: "100%", display: "flex", flexDirection: "column", background: token.colorBgContainer }}
      bodyStyle={{ flex: 1, padding: 0, overflow: "hidden", position: "relative" }}
    >
      <MapContainer 
        center={initialCenter} 
        zoom={15} 
        style={{ width: "100%", height: "100%", zIndex: 0 }}
      >
        <TileLayer
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
          attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
        />
        <MapController 
          selectedCamera={activeCamera} 
          selectedSite={activeSite || MOCK_SITES[0]}
          selectedCameraId={selectedCameraId}
          markerRefs={markerRefs}
          isMaximized={isMaximized} 
        />
        
        {siteBoundaries.map(sb => (
          <Polygon
            key={`site-bound-${sb.id}`}
            positions={sb.boundary}
            pathOptions={{
              color: "#d46b08",
              fill: false,
              dashArray: "10, 10",
              weight: 2
            }}
          />
        ))}

        {sites.map(site => (
          <Marker 
            key={site.id} 
            position={site.location}
            icon={siteIcon}
            zIndexOffset={1000}
            eventHandlers={{ click: () => onSiteSelect(site.id) }}
          >
            <Tooltip permanent direction="top" offset={[0, -50]}>
              <span style={{ fontWeight: 600, color: "#d46b08" }}>{site.name}</span>
            </Tooltip>
            <Popup>
              <div style={{ padding: "4px 8px" }}>
                <h4 style={{ margin: "0 0 8px 0" }}>{site.name} ({t("map.hq")})</h4>
                <p style={{ margin: 0 }}>{t("map.zone_count", { count: site.zones.length })}</p>
                <p style={{ margin: 0 }}>{t("map.cam_count", { count: cameras.filter(c => c.siteId === site.id).length })}</p>
              </div>
            </Popup>
          </Marker>
        ))}

        {zones.map(zone => {
          const levelInfo = LEVEL_MAP[zone.avgLevel];
          return (
            <Polygon
              key={zone.id}
              positions={zone.boundary}
              pathOptions={{
                color: levelInfo.color,
                fillColor: levelInfo.color,
                fillOpacity: selectedZoneId === zone.id ? 0.5 : 0.25,
                weight: selectedZoneId === zone.id ? 4 : 2
              }}
              eventHandlers={{
                click: () => onZoneSelect(zone.id)
              }}
            >
              <Tooltip direction="center" opacity={0.8}>{zone.name}</Tooltip>
              <Popup>
                <strong>{zone.name}</strong><br />
                {t("video.level", { level: zone.avgLevel })}
              </Popup>
            </Polygon>
          );
        })}

        <MarkerClusterGroup chunkedLoading maxClusterRadius={50} animate={true}>
          {cameras.map(cam => {
            const isSelected = selectedCameraId === cam.id;
            const levelInfo = LEVEL_MAP[cam.level];
            const isDanger = cam.level >= 5;

            return (
              <Marker 
                key={cam.id} 
                position={[cam.lat, cam.lng]}
                icon={getCameraIcon(cam.level, isSelected)}
                ref={el => { markerRefs.current[cam.id] = el; }}
                zIndexOffset={isSelected ? 500 : 100}
                eventHandlers={{ 
                  click: () => onCameraSelect(cam.id),
                  popupopen: () => {
                    if (selectedCameraId !== cam.id) {
                      onCameraSelect(cam.id);
                    }
                  }
                }}
              >
                <Tooltip direction="top" offset={[0, -20]} opacity={0.9}>
                  <div style={{ fontWeight: "bold" }}>{cam.name}</div>
                  <div style={{ fontSize: 13, color: levelInfo.color, fontWeight: "bold" }}>
                    {t("video.level", { level: cam.level })}
                  </div>
                </Tooltip>
                <Popup 
                  minWidth={240} 
                  autoPan={true} 
                  autoPanPadding={[50, 100]} // Extra padding for better top-centering
                  keepInView={true}
                >
                  <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
                    <MockVideoPlayer 
                      cameraId={cam.id} 
                      fps={3} 
                      fallbackUrl={cam.imageUrl}
                      style={{ width: "100%", aspectRatio: "16/9", borderRadius: 4, overflow: "hidden" }}
                    />
                    <div style={{ padding: "4px 2px" }}>
                      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
                        <div style={{ fontWeight: 800, fontSize: 18, color: token.colorText, letterSpacing: "-1px" }}>{cam.name}</div>
                        <div style={{ 
                          background: `${levelInfo.color}15`, 
                          color: levelInfo.color, 
                          padding: "4px 12px", 
                          borderRadius: 6, 
                          border: `1px solid ${levelInfo.color}`,
                          fontWeight: 800, 
                          fontSize: 20,
                          lineHeight: 1.2,
                          boxShadow: `0 2px 8px ${levelInfo.color}30`
                        }}>
                          {t("video.level", { level: cam.level })}
                        </div>
                      </div>
                      <div style={{ height: 1, background: token.colorBorderSecondary, marginBottom: 8, opacity: 0.5 }} />
                      <div style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 13, color: token.colorTextDescription }}>
                        <span style={{ fontSize: 11, opacity: 0.7, textTransform: "uppercase" }}>Analysis:</span>
                        <span style={{ fontWeight: 600, color: token.colorTextSecondary }}>
                          {t("map.density", { val: cam.densityPerM2 })}
                        </span>
                      </div>
                    </div>
                  </div>
                </Popup>
              </Marker>
            );
          })}
        </MarkerClusterGroup>
      </MapContainer>
      <style>{`
        .leaflet-popup-content-wrapper {
          background: ${token.colorBgElevated} !important;
          color: ${token.colorText} !important;
          border: 1px solid ${token.colorBorderSecondary} !important;
          border-radius: 8px !important;
          padding: 0 !important;
          box-shadow: 0 8px 32px rgba(0,0,0,0.4) !important;
          backdrop-filter: blur(8px) !important;
        }
        .leaflet-popup-content {
          margin: 12px !important;
          line-height: inherit !important;
        }
        .leaflet-popup-tip {
          background: ${token.colorBgElevated} !important;
        }
        .leaflet-popup-close-button {
          color: ${token.colorTextSecondary} !important;
          top: 8px !important;
          right: 8px !important;
          font-weight: bold !important;
        }
        .leaflet-popup-close-button:hover {
          color: ${token.colorPrimary} !important;
          background: transparent !important;
        }
      `}</style>
    </Card>
  );
};

export default CrowdOSMMap;
