import React from "react";
import { Modal, Row, Col, Card, Tag, Typography, theme, ConfigProvider } from "antd";
import EChart from "@/framework/components/Chart/EChart";
import { ZoneInfo, MOCK_HISTORY, LEVEL_MAP } from "../data/mockData";
import { useI18n } from "@/framework/i18n/hooks";

const { Text, Title } = Typography;
const { useToken } = theme;

interface Props {
  zone: ZoneInfo | null;
  visible: boolean;
  onClose: () => void;
}

const ZoneDetailsModal: React.FC<Props> = ({ zone, visible, onClose }) => {
  const { token } = useToken();
  const { t } = useI18n(["dashboard"]);
  
  if (!zone) return null;

  const history = MOCK_HISTORY(zone.id, false);
  const currentLvl = zone.avgLevel;
  
  const levelColors = {
    1: token.colorSuccess,
    2: token.colorInfo,
    3: token.colorWarning,
    4: "#fa8c16", 
    5: token.colorError
  };

  const levelLabels = {
    1: t("modal.safe"),
    2: t("modal.normal"),
    3: t("modal.caution"),
    4: t("modal.crowded"),
    5: t("modal.danger")
  };

  const currentColor = levelColors[currentLvl] || token.colorTextSecondary;
  const currentLabel = levelLabels[currentLvl] || "";

  const cardBg = token.colorBgContainer;
  const layoutBg = token.colorBgLayout;
  const textColor = token.colorText;
  const subTextColor = token.colorTextSecondary;

  // Gauge Option
  const gaugeOption = {
    series: [
      {
        type: "gauge",
        startAngle: 180, endAngle: 0,
        center: ["50%", "85%"], radius: "110%",
        axisLine: {
          lineStyle: {
            width: 25,
            color: [[0.2, levelColors[1] + "40"], [0.4, levelColors[2] + "40"], [0.6, levelColors[3] + "40"], [0.8, levelColors[4] + "40"], [1, levelColors[5] + "40"]]
          }
        },
        progress: { show: true, width: 25, itemStyle: { color: currentColor, opacity: 0.8 } },
        pointer: { show: true, length: "70%", width: 12, itemStyle: { color: currentColor, borderColor: "#fff", borderWidth: 2 } },
        axisTick: { show: true, splitNumber: 5, distance: -25, length: 10, lineStyle: { color: "#fff", width: 2 } },
        splitLine: { show: true, distance: -25, length: 22, lineStyle: { color: "#fff", width: 3 } },
        axisLabel: { show: false }, detail: { show: false },
        data: [{ value: currentLvl }]
      },
      {
        type: "gauge",
        startAngle: 180, endAngle: 0,
        center: ["50%", "85%"], radius: "115%",
        axisLine: { lineStyle: { width: 5, color: [[1, token.colorBorderSecondary + "30"]] } },
        progress: { show: true, width: 5, itemStyle: { color: currentColor, shadowBlur: 10, shadowColor: currentColor } },
        axisTick: { show: false }, splitLine: { show: false }, axisLabel: { show: false }, detail: { show: false },
        data: [{ value: currentLvl }]
      }
    ]
  };

  // Area Chart Option
  const areaOption = {
    grid: { left: "12%", right: "8%", top: "15%", bottom: "15%" },
    xAxis: {
      type: "category",
      data: history.map(h => h.time),
      boundaryGap: false,
      axisLabel: { interval: 9, fontSize: 10, color: subTextColor }
    },
    yAxis: {
      type: "value",
      min: 0, max: 240, interval: 40,
      splitLine: { show: true, lineStyle: { type: "dashed", color: token.colorBorderSecondary } },
      axisLabel: {
        fontSize: 10,
        color: subTextColor,
        formatter: (val: number) => {
          const map: Record<number, string> = { 40: t("modal.safe"), 80: t("modal.normal"), 120: t("modal.caution"), 160: t("modal.crowded"), 200: t("modal.danger") };
          return map[val] || "";
        }
      }
    },
    visualMap: {
      show: false,
      pieces: [[0, 40, levelColors[1]], [40, 80, levelColors[2]], [80, 120, levelColors[3]], [120, 160, levelColors[4]], [160, 240, levelColors[5]]].map(([gt, lte, color]) => ({ gt, lte, color }))
    },
    series: [
      {
        data: history.map(h => h.count),
        type: "line", smooth: true, showSymbol: true, symbolSize: 6,
        areaStyle: {
          opacity: 0.5,
          color: { type: 'linear', x: 0, y: 0, x2: 0, y2: 1, colorStops: [{ offset: 0, color: currentColor }, { offset: 1, color: "rgba(255,255,255,0)" }] }
        },
        lineStyle: { width: 3, color: currentColor },
        markLine: {
          silent: true, symbol: ["none", "arrow"],
          lineStyle: { color: levelColors[5], type: "dashed", width: 2 },
          data: [{ yAxis: 200, label: { formatter: t("modal.danger").toUpperCase(), position: "end", color: levelColors[5], fontWeight: "bold" } }]
        },
        markPoint: { data: [{ type: "max", name: t("modal.peak") }], symbolSize: 40, itemStyle: { color: levelColors[5] } }
      }
    ]
  };

  return (
    <ConfigProvider
      theme={{
        token: {
          colorBgElevated: cardBg, // This targets the Modal Background natively in AntD v5
          colorBgContainer: cardBg,
        }
      }}
    >
      <Modal
        title={
          <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
            <Tag color="geekblue" style={{ borderRadius: 12, border: "none" }}>{zone.id.split("_")[1]}</Tag>
            <Title level={4} style={{ margin: 0, color: textColor, fontWeight: 700 }}>{zone.name}</Title>
            <Text style={{ marginLeft: "auto", marginRight: 24, fontSize: 13, fontWeight: 700, color: textColor }}>
              {t("modal.risk_title")}
            </Text>
          </div>
        }
        open={visible}
        onCancel={onClose}
        footer={null}
        width={780}
        centered
        className="crowdsafe-modal"
        styles={{ 
          mask: { backdropFilter: "blur(6px)", backgroundColor: "rgba(0, 0, 0, 0.45)" },
          header: { background: "transparent", borderBottom: `1px solid ${token.colorBorderSecondary}`, padding: "16px 24px", margin: 0 },
          body: { background: "transparent", padding: "24px", color: textColor }
        }}
      >
        <Row gutter={[24, 24]}>
          <Col span={15}>
            <Card 
              size="small" variant="borderless" 
              style={{ background: layoutBg, borderRadius: 12, height: 280 }}
              bodyStyle={{ padding: "8px" }}
            >
              <EChart option={areaOption} style={{ height: 260, width: "100%" }} />
            </Card>
          </Col>

          <Col span={9}>
            <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
              <Card 
                size="small" variant="borderless" 
                style={{ height: 180, borderRadius: 12, overflow: "hidden", background: layoutBg }} 
                bodyStyle={{ padding: 0, height: "100%", display: "flex", justifyContent: "center", alignItems: "center" }}
              >
                <EChart option={gaugeOption} style={{ height: 170, width: "100%" }} />
              </Card>
              
              <Card 
                size="small" variant="borderless"
                style={{ background: currentColor + "20", border: `1px solid ${currentColor}40`, borderRadius: 12, padding: "8px" }}
              >
                <div style={{ textAlign: "right" }}>
                  <Text style={{ fontSize: 13, display: "block", marginBottom: 4, color: textColor, opacity: 0.8 }}>{t("modal.current_status")}</Text>
                  <div style={{ fontSize: 32, fontWeight: 900, color: currentColor, lineHeight: 1.2 }}>
                    {currentLabel}
                  </div>
                </div>
              </Card>
            </div>
          </Col>

          <Col span={24}>
            <div style={{ marginTop: 8 }}>
              <Title level={5} style={{ fontSize: 15, marginBottom: 16, display: "flex", alignItems: "center", gap: 8, color: textColor }}>
                 <span style={{ width: 4, height: 16, background: token.colorPrimary, borderRadius: 2 }} />
                {t("modal.legend_title")}
              </Title>
              <Row gutter={8}>
                {[
                  { label: t("modal.safe"), range: "~40", color: levelColors[1] },
                  { label: t("modal.normal"), range: "~80", color: levelColors[2] },
                  { label: t("modal.caution"), range: "~120", color: levelColors[3] },
                  { label: t("modal.crowded"), range: "~160", color: levelColors[4] },
                  { label: t("modal.danger"), range: "200 " + (t("dashboard:stats.legend_count") || "ppl"), color: levelColors[5] }
                ].map(item => (
                  <Col span={4.8} key={item.label} style={{ width: "20%" }}>
                    <div style={{ background: item.color, padding: "12px 0", textAlign: "center", borderRadius: "8px 8px 0 0" }}>
                      <Text style={{ fontWeight: 800, fontSize: 14, color: "#fff" }}>{item.label}</Text>
                    </div>
                    <div style={{ 
                      background: layoutBg, padding: "8px 0", textAlign: "center", fontSize: 12, 
                      border: `1px solid ${token.colorBorderSecondary}`, borderTop: "none",
                      borderRadius: "0 0 8px 8px", color: textColor, fontWeight: 600
                    }}>
                      {item.range}
                    </div>
                  </Col>
                ))}
              </Row>
              <div style={{ textAlign: "right", marginTop: 12, color: subTextColor, fontSize: 11, fontWeight: 500 }}>
                {t("modal.unit_persons")}
              </div>
            </div>
          </Col>
        </Row>
      </Modal>
    </ConfigProvider>
  );
};

export default ZoneDetailsModal;
