import React from "react";
import EChart from "@/framework/components/Chart/EChart";
import { CrowdHistory, LEVEL_MAP } from "../data/mockData";
import { Card, Empty, theme } from "antd";
import { BarChartOutlined } from "@ant-design/icons";
import { useI18n } from "@/framework/i18n/hooks";

const { useToken } = theme;

interface Props {
  history: CrowdHistory[];
  title: string;
  extra?: React.ReactNode;
}

const CrowdStatsChart: React.FC<Props> = ({ history, title, extra }) => {
  const { token } = useToken();
  const { t } = useI18n(["dashboard"]);

  const option = {
    tooltip: {
      trigger: "axis",
      backgroundColor: "rgba(26, 26, 26, 0.8)",
      borderColor: token.colorBorderSecondary,
      textStyle: { color: token.colorText, fontSize: 12 },
      extraCssText: `box-shadow: 0 8px 32px rgba(0,0,0,0.5); backdrop-filter: blur(8px); border-radius: 8px;`,
      axisPointer: { type: "cross", label: { backgroundColor: token.colorPrimary } }
    },
    dataZoom: [
      {
        type: "inside",
        start: 0,
        end: 100,
        zoomOnMouseWheel: true,
        moveOnMouseMove: true,
        moveOnMouseWheel: false
      }
    ],
    legend: {
      data: [t("stats.legend_count"), t("stats.legend_stage")],
      top: 10,
      textStyle: { color: token.colorTextSecondary }
    },
    grid: { left: "1%", right: 60, bottom: "5%", containLabel: true, top: 40 },
    xAxis: {
      type: "category",
      data: history.map(h => h.time),
      axisLabel: { color: token.colorTextSecondary, fontSize: 10 }
    },
    yAxis: [
      { 
        type: "value", 
        name: t("stats.axis_people"), 
        minInterval: 1,
        axisLabel: { color: token.colorTextSecondary }
      },
      { 
        type: "value", 
        name: t("stats.axis_stage"), 
        min: 0, 
        max: 6, 
        interval: 1, 
        splitLine: { show: false },
        axisLabel: { show: false } // Hide redundant y-axis labels to avoid overlap with markLine labels
      }
    ],
    series: [
      {
        name: t("stats.legend_count"),
        type: "bar",
        data: history.map(h => h.count),
        itemStyle: { 
          color: (params: any) => {
            const count = params.value;
            if (count > 160) return LEVEL_MAP[5].color;
            if (count > 120) return LEVEL_MAP[4].color;
            if (count > 80) return LEVEL_MAP[3].color;
            if (count > 40) return LEVEL_MAP[2].color;
            return LEVEL_MAP[1].color;
          }
        },
        markPoint: {
          data: [{ type: "max", name: t("stats.peak"), itemStyle: { color: token.colorError } }],
          label: { fontSize: 10, color: "#fff" }
        }
      },
      {
        name: t("stats.legend_stage"),
        type: "line",
        yAxisIndex: 1,
        z: 10, // Ensure line is above bars
        smooth: true,
        showSymbol: true,
        symbolSize: 6,
        data: history.map(h => h.avgLevel),
        itemStyle: { color: token.colorError },
        lineStyle: { width: 3, type: "dashed", opacity: 0.8 },
        markLine: {
          silent: true,
          symbol: "none",
          label: { 
            position: "end", 
            fontSize: 10, 
            color: token.colorTextSecondary,
            distance: 8
          },
          lineStyle: { opacity: 0.5, type: "dashed" },
          data: [
            { yAxis: 1, label: { formatter: t("video.level", { level: 1 }) }, lineStyle: { color: LEVEL_MAP[1].color } },
            { yAxis: 2, label: { formatter: t("video.level", { level: 2 }) }, lineStyle: { color: LEVEL_MAP[2].color } },
            { yAxis: 3, label: { formatter: t("video.level", { level: 3 }) }, lineStyle: { color: LEVEL_MAP[3].color } },
            { yAxis: 4, label: { formatter: t("video.level", { level: 4 }) }, lineStyle: { color: LEVEL_MAP[4].color, opacity: 0.8 } },
            { yAxis: 5, label: { formatter: t("video.level", { level: 5 }) }, lineStyle: { color: token.colorError, type: "solid", width: 2, opacity: 1 } }
          ]
        }
      }
    ]
  };

  return (
    <Card 
      title={
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <BarChartOutlined style={{ color: token.colorPrimary }} />
          <span style={{ color: token.colorText }}>{t("stats.title")} ({title})</span>
        </div>
      }
      extra={extra}
      size="small"
      style={{ height: "100%", display: "flex", flexDirection: "column", background: token.colorBgContainer }}
      bodyStyle={{ flex: 1, padding: 8, overflow: "hidden" }}
    >
      {history.length > 0 ? (
        <EChart 
          option={option} 
          style={{ height: "100%", width: "100%" }} 
        />
      ) : (
        <Empty description={t("stats.no_data")} />
      )}
    </Card>
  );
};

export default CrowdStatsChart;
