import React, { useMemo } from "react";
import { Card, Badge, Empty, Tag, Radio, Space, theme, Select } from "antd";
import { VideoCameraOutlined, AlertOutlined, GlobalOutlined } from "@ant-design/icons";
import { CameraInfo, LEVEL_MAP, ZoneInfo } from "../data/mockData";
import { useI18n } from "@/framework/i18n/hooks";
import { MockVideoPlayer } from "../hooks/useCameraMock";

const { useToken } = theme;

interface Props {
  cameras: CameraInfo[];
  zones: ZoneInfo[];
  selectedZoneId?: string | null;
  onZoneSelect?: (id: string | null) => void;
  layoutCount: number;
  onLayoutChange: (count: number) => void;
  startIndex: number;
  onStartIndexChange: (index: number) => void;
  selectedCameraId?: number | null;
  onCameraSelect?: (id: number) => void;
  onCameraDoubleClick?: (id: number) => void;
  extra?: React.ReactNode;
}

const CrowdVideoMonitor: React.FC<Props> = ({ 
  cameras, 
  zones,
  selectedZoneId,
  onZoneSelect,
  layoutCount,
  onLayoutChange,
  startIndex,
  onStartIndexChange,
  selectedCameraId,
  onCameraSelect,
  onCameraDoubleClick,
  extra
}) => {
  const { token } = useToken();
  const { t } = useI18n(["dashboard"]);
  
  // Filtering is handled by parent, but we display the filtered set
  const displayedCameras = useMemo(() => {
    return cameras.slice(startIndex, startIndex + layoutCount);
  }, [cameras, startIndex, layoutCount]);

  const cols = Math.ceil(Math.sqrt(layoutCount));

  const cameraOptions = useMemo(() => {
    const total = cameras.length;
    const options = [];
    if (layoutCount === 1) {
      for (let i = 0; i < total; i++) {
        options.push({ value: i, label: `${cameras[i].name}` });
      }
    } else {
      for (let i = 0; i < total; i += layoutCount) {
        const end = Math.min(i + layoutCount, total);
        options.push({
          value: i,
          label: `${t("video.channel_range", { start: i + 1, end: end })}` || `Ch ${i+1} - ${end}`,
        });
      }
    }
    return options;
  }, [cameras, layoutCount, t]);

  const zoneOptions = useMemo(() => {
    return [
      { label: t("header.plant_all"), value: "ALL" },
      ...zones.map(z => ({ label: z.name, value: z.id }))
    ];
  }, [zones, t]);

  const getOverlayStyles = (count: number) => {
    switch (count) {
      case 1: return { name: 18, tag: 14, badge: 16, alert: 24, padding: "4px 10px" };
      case 4: return { name: 14, tag: 11, badge: 12, alert: 18, padding: "2px 6px" };
      case 9: return { name: 11, tag: 9, badge: 10, alert: 14, padding: "1px 4px" };
      case 16: return { name: 9, tag: 8, badge: 9, alert: 12, padding: "0px 3px" };
      default: return { name: 14, tag: 11, badge: 12, alert: 18, padding: "2px 6px" };
    }
  };

  const styles = getOverlayStyles(layoutCount);

  return (
    <Card 
      title={
        <div style={{ display: "flex", alignItems: "center", gap: 12, flexWrap: "wrap", justifyContent: "space-between", width: "100%" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <VideoCameraOutlined style={{ color: token.colorPrimary }} />
            <span style={{ fontWeight: 600, color: token.colorText, whiteSpace: "nowrap" }}>{t("video.title")}</span>
            
            {/* Zone Selector */}
            <Select
              size="small"
              value={selectedZoneId || "ALL"}
              onChange={(val) => onZoneSelect?.(val === "ALL" ? null : val)}
              options={zoneOptions}
              style={{ minWidth: 120, marginLeft: 4 }}
              variant="borderless"
              popupMatchSelectWidth={false}
              suffixIcon={<GlobalOutlined style={{ fontSize: 10 }} />}
            />

            <Select
              size="small"
              value={startIndex}
              onChange={onStartIndexChange}
              options={cameraOptions}
              style={{ minWidth: 130 }}
              suffixIcon={<VideoCameraOutlined style={{ fontSize: 10 }} />}
              variant="filled"
            />
          </div>
          <Space size={8}>
            <Radio.Group 
              size="small" 
              value={layoutCount} 
              onChange={(e) => {
                onLayoutChange(e.target.value);
                onStartIndexChange(0); // Reset to first page
              }}
              buttonStyle="solid"
            >
              {[1, 4, 9, 16].map(val => (
                <Radio.Button key={val} value={val} style={{ width: 44, textAlign: "center", padding: 0 }}>
                  {val}
                </Radio.Button>
              ))}
            </Radio.Group>
          </Space>
        </div>
      }
      extra={extra}
      size="small"
      style={{ height: "100%", display: "flex", flexDirection: "column", background: token.colorBgContainer }}
      bodyStyle={{ flex: 1, padding: 8, overflow: "hidden" }}
    >
      {displayedCameras.length > 0 ? (
        <div style={{
          display: "grid",
          gridTemplateColumns: `repeat(${cols}, 1fr)`,
          gridTemplateRows: `repeat(${cols}, 1fr)`,
          gap: 6,
          height: "100%"
        }}>
          {displayedCameras.map(cam => {
            const isSelected = selectedCameraId === cam.id;
            const levelInfo = LEVEL_MAP[cam.level] || LEVEL_MAP[1];
            const isDanger = cam.level >= 5;

            return (
              <div 
                key={cam.id} 
                onClick={() => onCameraSelect?.(cam.id)}
                onDoubleClick={() => onCameraDoubleClick?.(cam.id)}
                style={{ 
                  position: "relative", 
                  background: "#000", 
                  borderRadius: token.borderRadiusSM, 
                  overflow: "hidden",
                  cursor: "pointer",
                  border: isSelected 
                    ? `2px solid ${token.colorPrimary}` 
                    : isDanger ? `1.5px solid ${token.colorError}` : `1px solid ${token.colorBorderSecondary}`,
                  boxShadow: isSelected ? `0 0 8px ${token.colorPrimary}60` : "none",
                  animation: isDanger ? "pulse-border 1.5s infinite" : "none"
                }}
              >
                <MockVideoPlayer 
                  cameraId={cam.id} 
                  fps={3} 
                  fallbackUrl={cam.imageUrl}
                  style={{ width: "100%", height: "100%", opacity: isSelected ? 1 : 0.8 }}
                />
                
                <div style={{ 
                  position: "absolute", 
                  top: 4, 
                  left: 4, 
                  background: "rgba(0,0,0,0.6)", 
                  color: "#fff", 
                  padding: styles.padding, 
                  fontSize: styles.name,
                  fontWeight: 600,
                  borderRadius: 2,
                  zIndex: 10,
                  textShadow: "1px 1px 2px #000" // Add visibility against bright backgrounds
                }}>
                  {cam.name}
                </div>

                {isDanger && (
                  <div style={{ position: "absolute", top: 4, right: 4, zIndex: 10 }}>
                    <AlertOutlined style={{ color: token.colorError, fontSize: styles.alert, filter: "drop-shadow(0 0 4px #000)" }} />
                  </div>
                )}

                <div style={{ 
                  position: "absolute", 
                  bottom: 4, 
                  left: 4,
                  right: 4,
                  display: "flex", 
                  justifyContent: "flex-start",
                  alignItems: "flex-end",
                  zIndex: 10
                }}>
                  <Tag 
                    color={levelInfo.color} 
                    style={{ 
                      fontSize: styles.tag, 
                      margin: 0, 
                      padding: "0 6px",
                      lineHeight: "1.5",
                      border: "1px solid rgba(0,0,0,0.2)",
                      fontWeight: 700,
                      textShadow: "0 0 1px #000", // Subtle outline for contrast
                      boxShadow: "0 2px 4px rgba(0,0,0,0.3)"
                    }}
                  >
                    {t("video.level", { level: cam.level })}
                  </Tag>
                </div>
              </div>
            );
          })}
          {Array.from({ length: layoutCount - displayedCameras.length }).map((_, i) => (
            <div key={`empty-${i}`} style={{ background: token.colorBgContainerDisabled, borderRadius: 4, border: `1px dashed ${token.colorBorder}` }} />
          ))}
        </div>
      ) : (
        <Empty description={t("video.no_video")} />
      )}
      <style>{`
        @keyframes pulse-border {
          0% { border-color: ${token.colorError}; }
          50% { border-color: ${token.colorErrorActive}; }
          100% { border-color: ${token.colorError}; }
        }
      `}</style>
    </Card>
  );
};

export default CrowdVideoMonitor;
