import { useState, useEffect, useMemo } from "react";
import React from "react";

/**
 * Global Clock for Camera Mock Frames (Singleton Pattern)
 */
let globalFrameIndex = 0;
const listeners = new Set<(frame: number) => void>();
let globalInterval: any = null;

function startGlobalClock(fps = 3) {
  if (globalInterval) return;
  globalInterval = setInterval(() => {
    globalFrameIndex = (globalFrameIndex + 1) % 10000;
    listeners.forEach(fn => fn(globalFrameIndex));
  }, 1000 / fps);
}

export function useCameraMockSync(fps = 3) {
  const [frameIndex, setFrameIndex] = React.useState(globalFrameIndex);

  React.useEffect(() => {
    startGlobalClock(fps);
    const handler = (frame: number) => setFrameIndex(frame);
    listeners.add(handler);
    return () => {
      listeners.delete(handler);
      // Optional: stop clock if no listeners
      if (listeners.size === 0 && globalInterval) {
        clearInterval(globalInterval);
        globalInterval = null;
      }
    };
  }, [fps]);

  return frameIndex;
}

/**
 * Hook to manage CrowedSafe Camera Mock Assets
 */
export function useCameraMock() {
  const assets = useMemo(() => {
    // Import all images from mockup/imgMock
    const modules = import.meta.glob("../../../mockup/imgMock/**/*.{jpg,JPG,png,PNG}", {
      eager: true,
      query: "?url",
      import: "default",
    });

    const assetMap: Record<string, string[]> = {};

    Object.entries(modules).forEach(([path, url]) => {
      const normalizedPath = path.replace(/\\/g, '/');
      const parts = normalizedPath.split('/');
      
      if (parts.length >= 2) {
        const folder = parts[parts.length - 2];
        if (!assetMap[folder]) assetMap[folder] = [];
        assetMap[folder].push(url as string);
      }
    });

    // Sort filenames in each folder to ensure sequence
    Object.keys(assetMap).forEach(key => {
      assetMap[key].sort();
    });

    const folderKeys = Object.keys(assetMap)
      .filter(k => /^\d+$/.test(k))
      .sort((a, b) => Number(a) - Number(b));

    return { assetMap, folderKeys };
  }, []);

  return assets;
}

/**
 * Gets the Mock URL for a Specific Camera
 */
export function getCameraImgUrl(
  cameraId: number, 
  frameIndex: number, 
  assets: { assetMap: Record<string, string[]>; folderKeys: string[] }
) {
  const { assetMap, folderKeys } = assets;
    
  if (folderKeys.length === 0) return "";
  
  // Use camera ID (offset by 100) to pick a folder consistently
  // Ensure we handle potential negative or very large IDs safely
  const indexOffset = Math.max(0, cameraId - 100);
  const folderKey = folderKeys[indexOffset % folderKeys.length];
  const folderImages = assetMap[folderKey];

  if (!folderImages || folderImages.length === 0) return "";

  const localIndex = Math.abs(frameIndex) % folderImages.length;
  return folderImages[localIndex];
}

/**
 * Hook that returns the current mock image URL for a camera
 */
export function useCameraMockUrl(cameraId: number, fps = 2) {
  const frameIndex = useCameraMockSync(fps);
  const assets = useCameraMock();
  return getCameraImgUrl(cameraId, frameIndex, assets);
}

/**
 * A specialized component to play mock video without flickering
 * and without re-rendering the parent component.
 */
export const MockVideoPlayer: React.FC<{
  cameraId: number;
  fps?: number;
  style?: React.CSSProperties;
  className?: string;
  fallbackUrl?: string;
}> = ({ cameraId, fps = 3, style, className, fallbackUrl }) => {
  const frameIndex = useCameraMockSync(fps);
  const assets = useCameraMock();
  const currentUrl = useMemo(() => getCameraImgUrl(cameraId, frameIndex, assets) || fallbackUrl, [cameraId, frameIndex, assets, fallbackUrl]);
  const nextUrl = useMemo(() => getCameraImgUrl(cameraId, frameIndex + 1, assets), [cameraId, frameIndex, assets]);

  const [isError, setIsError] = useState(false);
  
  // Reset error state when URL changes
  useEffect(() => {
    setIsError(false);
  }, [currentUrl]);

  return (
    <div 
      className={className} 
      style={{ 
        ...style, 
        position: "relative", 
        overflow: "hidden",
        backgroundColor: "#141414",
        display: "flex",
        alignItems: "center",
        justifyContent: "center"
      }}
    >
      {/* Hidden preloader for the next frame to prevent flickering */}
      {nextUrl && (
        <img
          src={nextUrl}
          style={{ display: "none" }}
          alt="preloader"
        />
      )}
      
      {isError ? (
        <div style={{ color: "rgba(255,255,255,0.3)", fontSize: 11, textAlign: "center", padding: 8 }}>
          VIDEO SIGNAL LOST<br/>(ID: {cameraId})
        </div>
      ) : (
        <img
          src={currentUrl}
          alt={`camera-${cameraId}`}
          onError={() => setIsError(true)}
          style={{ 
            width: "100%", 
            height: "100%", 
            objectFit: "cover", 
            display: "block",
            transition: "opacity 0.2s ease-in-out" 
          }}
        />
      )}
      
      {/* Overlay for camera info (Removed as redundant in grid view) */}
    </div>
  );
};
